#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MOD 1000000007

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

long long power(long long base, int exponent) {
    long long result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % MOD;
        }
        base = (base * base) % MOD;
        exponent /= 2;
    }
    return result;
}

long long inverse(long long num) {
    return power(num, MOD - 2);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[100005];
        scanf("%s", A);
        int n = strlen(A);
        int freq[26] = {0};
        for (int i = 0; i < n; i++) {
            freq[A[i] - 'a']++;
        }
        long long total_permutations = factorial(n);
        for (int i = 0; i < 26; i++) {
            total_permutations = (total_permutations * inverse(factorial(freq[i]))) % MOD;
        }
        long long similar_strings = 0;
        for (int i = 0; i < 26; i++) {
            for (int j = i + 1; j < 26; j++) {
                if (freq[i] > 0 && freq[j] > 0) {
                    similar_strings = (similar_strings + (freq[i] * freq[j]) % MOD) % MOD;
                }
            }
        }
        printf("%lld\n", ((total_permutations * total_permutations) % MOD - similar_strings * 2 % MOD + MOD) % MOD);
    }
    return 0;
}

